__kernel void hotspotOpt1(__global const float* pIn,
                          __global const float* tIn,
                          __global float* tOut,
                          const float stepDivCap,
                          const int nx,
                          const int ny,
                          const int nz,
                          const float ce,
                          const float cw,
                          const float cn,
                          const float cs,
                          const float ct,
                          const float cb,
                          const float cc)
{
    int x = get_global_id(0);
    int y = get_global_id(1);

    if (x >= nx || y >= ny) return;

    for (int z = 0; z < nz; z++) {
        int c = x + y * nx + z * nx * ny;

        int w = (x == 0) ? c : c - 1;
        int e = (x == nx - 1) ? c : c + 1;
        int n = (y == 0) ? c : c - nx;
        int s = (y == ny - 1) ? c : c + nx;
        int b = (z == 0) ? c : c - nx * ny;
        int t = (z == nz - 1) ? c : c + nx * ny;

        tOut[c] = cc * tIn[c] + cw * tIn[w] + ce * tIn[e]
                + cs * tIn[s] + cn * tIn[n] + cb * tIn[b] + ct * tIn[t]
                + (stepDivCap) * pIn[c] + ct * 80.0f; // amb_temp is 80.0 from global context
    }
}
